module top_module(
    input [7:0] A,
    input [7:0] B,
    output [7:0] sum,
    output carry_out
);wire [8:0] sum_result;

    // Add A and B, store result in sum_result
    assign sum_result = {1'b0, A} + {1'b0, B};

    // Assign sum to the 8 least significant bits of sum_result
    assign sum = sum_result[7:0];

    // Assign carry_out to the most significant bit of sum_result
    assign carry_out = sum_result[8];

endmodule
